import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"回力标系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/回力标系列.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/回力标系列.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/回力标系列.md"};function o(d,b,_,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"回力标系列",tabindex:"-1"},[t("回力标系列 "),r("a",{class:"header-anchor",href:"#回力标系列","aria-label":'Permalink to "回力标系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="回力标系列-1" tabindex="-1">回力标系列 <a class="header-anchor" href="#回力标系列-1" aria-label="Permalink to &quot;回力标系列&quot;">​</a></h1><p>回力标系列<br> 描述：传说之宝系列的武器，其中回力标并不是错字，而是游戏中所有武器都用的是【回力标】而不是【回力镖】。此外，虽然是回力标系列，但下属还包含了一些其他装备。<br> 【若无特殊说明，该系列武器需要逐级购买，购买高等级后将保留低等级武器的效果。】</p><p>回力标-基础<br> 价格：D+500<br> 分类：投掷武器<br> 描述：基础款式的回力标，没什么特别的，唯一的效果是在投掷后可以自动回到手中。<br> 武器伤害：5L<br> 武器特性：【高速1】【破甲1】【回力】<br> 射程：敏捷属性*5米<br> 伤害类型：物理-挥砍<br> 额外效果：无</p><p>回力标-月牙<br> 前置：回力标-基础<br> 价格：C+1000<br> 分类：投掷武器<br> 描述：月牙形状的回力标，上面蕴含着淡淡的魔力，可以增加攻击的性能。<br> 武器伤害：13L<br> 武器特性：【高速1】【破甲1】【回力】【8加骰】<br> 射程：敏捷属性*5米<br> 伤害类型：物理-挥砍<br> 额外效果：无</p><p>回力标-手里剑<br> 前置：回力标-月牙<br> 价格：B+2000<br> 分类：投掷武器<br> 描述：手里剑形状的回力标，能够增加攻击次数，可以一次性散射出大量回力标（当然，回力后你手中依旧只有一枚可以使用的回力标）。<br> 武器伤害：30L<br> 武器特性：【高速1】【破甲1】【回力】【8加骰】【连射】<br> 射程：敏捷属性*5米<br> 伤害类型：物理-挥砍</p><p>额外效果：每轮一次，当你使用【回力标-手里剑】进行投掷攻击时，附带一次无法使用招式的普通投掷攻击。<br> 特殊的是，【回力标-手里剑】的连射无需消费弹药，只在画面上表现为散射出大量的手里剑形状的回力标。</p><p>凤凰<br> 价格：B+2500（独立购买）<br> 描述：宛如盘旋在手臂上的鸟儿一样的回力标，可以使用风属性的攻击。<br> 武器伤害：24L<br> 武器特性：【高速2】【回力】【8加骰】<br> 射程：敏捷属性*5米<br> 伤害类型：物理-音波（震动）<br> 额外效果：持有者获得技能-凤翔天翼。</p><p>【凤翔天翼】<br> 动作：标准动作<br> 消耗：无<br> 范围：见下<br> 目标：见下<br> 效果：你进行一次普通投掷攻击，本次攻击同时攻击等同武器射程范围内的所有单位，同时攻击出目将增加一半，每轮这个效果只会生效一次。</p><p>【回力标下属技艺/改装】<br> 回力标-星<br> 价格：D+500<br> 动作：标准动作<br> 消耗：无<br> 射程：武器射程/2<br> 描述：附加星型花纹的回力标可以提升幸运值，使攻击在目标之间反复弹射。<br> 效果：<br> 消费一个标准动作，你进行一次普通投掷攻击，本次攻击获得1DP技艺加值，同时攻击等同射程范围内的所有敌人。</p><p>回力标-云<br> 前置：回力标-星<br> 价格：C+1500<br> 动作：标准动作<br> 射程：见下<br> 描述：附加云雾花纹的回力标势大力沉，除了可以造成范围伤害外，还具有额外的输出效果提升。<br> 效果：<br> 消费一个标准动作，你进行一次普通投掷攻击，本次攻击获得自身敏捷属性*1点技艺加值，同时攻击等同射程范围内的所有敌人。</p><p>回力标-械<br> 价格：D+1000<br> 分类：改装<br> 描述：使用机械工艺改装回力标，为回力标增加额外的破甲能力。<br> 效果：<br> 改装后的回力标具有【破甲10】，同时在命中后追加1点物理-挥砍伤害，与攻击一同计算，只处理一次对应的减伤类能力影响。</p><p>回力标-炎/冰<br> 价格：C+1000<br> 分类：改装<br> 描述：使用附魔工艺对回力标进行处理，使回力标增加新的属性。<br> 效果：<br> 【你需要使用一个迅捷动作才能激活改装的效果，激活后效果持续一轮。】<br> 持续时间内，该回力标伤害改为火焰能量伤害或寒冷能量伤害，同时具有【破魔10】，若你对攻击出目不满意则可以进行一次重骰，必须接受重骰结果，每轮重骰只会生效一次。</p><p>【其他装备】<br> 变速护腕<br> 价格：D+500<br> 位置：手腕<br> 描述：外观看起来像是白色腕带的特殊护腕，上面施加了变速的附魔。<br> 效果：佩戴者的基础移动速度提升20米，同时在敏捷检定上获得5DP器械加值。<br> 特殊的是，购买者也可以选择获得闪避防御上的5点加值，而不是敏捷检定上的器械加值。</p><p>外部骨骼<br> 价格：C+1250<br> 位置：披风<br> 描述：全自动型外骨骼，在不需要的时候会伪装成披风的样式。<br> 效果：佩戴者的盔甲防御提升6点，同时在敏捷检定上获得6DP器械加值，以及具有基于盔甲防御的【坚韧】特性。<br> 若盔甲防御因其他原因而发生改变，则该物品提供的防御与坚韧将相应转变为对应的防御类型。</p><p>香奈儿皮靴<br> 价格：D+500<br> 分类：鞋袜<br> 描述：名牌皮靴，只是穿上就能感觉到自己气质得到了提升，这大概就是品牌效应吧（错误用法）。<br> 效果：穿戴者的外貌提升5点，同时在防御上获得5点无名防御。</p><p>轻羽之靴<br> 价格：C+1000<br> 位置：鞋袜<br> 描述：可以使穿戴者身轻如羽，并且增加移动速度的靴子，外观上看起来更像是白色的凉鞋。<br> 效果：穿戴者的基础移动速度提升30米，免疫自然坠落伤害。此外，轻羽之靴将提供8点偏斜防御，以及免疫C级困难地形的效果。</p><p>幸运红跑鞋<br> 价格：C+1000<br> 位置：鞋袜<br> 描述：红色三倍速，总而言之这双跑鞋可以让你跑的更快，同时也要更加幸运一些。<br> 效果：<br> 穿戴者的基础移动速度提升30米，同时在全检定上获得2DP幸运加值，以及获得2点机运检定加值，因此获得的机运加值无法与其他机运加值叠加生效。</p><p>盖亚护手<br> 价格：C+1000<br> 位置：手腕（手套）<br> 描述：精心打造的护腕，赠送一双棕色的品牌级手套，只要穿上这对护腕就可以获得盖亚的加持，如同大地一样难以撼动。<br> 效果：<br> 佩戴者在进行绊摔/冲撞/擒抱时，无视体积带来的优势与劣势。同时免疫不超过B级的接触攻击。若佩戴者不具有【防能量武器】特性，则获得【防能量武器特性】，否则将改为提供3点力场防御。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
